form:Form.form:Scripts:
		function aceptar_onclick()
{
	var verbo;
	if (Ctrl('main').GetMode()=="APROBAR") accion = "aprobar el/los Pedido/s de Liquidación Final";
	else if (Ctrl('main').GetMode()=="RECHAZAR") accion = "rechazar el/los Pedido/s de Liquidación Final";
	else if (Ctrl('main').GetMode()=="ANULAR") accion = "anular el Pedido de Liquidación Final";

  var resp = confirm("¿Está seguro que desea " + accion + "?");
  return resp;
}

